on conflict (name) do update set sort_order = excluded.sort_order;

  baby_name,
  event_title,
  event_date,
  event_time,
  address,
  address_reference,
  google_maps_url,
  google_maps_embed_url,
  pix_key,
  pix_receiver_name,
  pix_city,
  pix_bank,
  invitation_message,
  final_message
)
select
  'Liara',
  'Cha de Bebe da Liara',
  '2026-08-02',
  '14:00',
  'Rua Santiago, 236 - Serrinha, Fortaleza - CE',
  'Espaço de eventos Felix',
  'https://maps.app.goo.gl/8xsQsqPHuxQkFhiS7',
  'https://www.google.com/maps?q=Rua+Santiago+236+Serrinha+Fortaleza+CE&output=embed',
  '075.650.053-20',
  'Tiala Debora Fernandes Nobre',
  'Fortaleza',
  'Santander',
  'Com muito amor, estamos preparando a chegada da nossa pequena Liara e gostariamos de compartilhar esse momento especial com voce.',
  'Obrigada por fazer parte desse momento tao especial.'
where not exists (select 1 from public.event_settings);

with categories as (
  select id, name from public.gift_categories
)
on conflict (seed_code) do update set
  category_id = excluded.category_id,
  name = excluded.name,
  estimated_value = excluded.estimated_value,
  suggested_brands = excluded.suggested_brands,
  sort_order = excluded.sort_order;
